class Solution:
    def strWithout3a3b(self, a: int, b: int) -> str:
        result = []
        while a > 0 or b > 0:
            if a >= b and a > 0:
                result.append('a')
                a -= 1
            elif b > a and b > 0:
                result.append('b')
                b -= 1
            elif a > 0:
                result.append('a')
                a -= 1
            else:
                result.append('b')
                b -= 1
        return ''.join(result)
